import{_ as e,o as d,c as o,a2 as r}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Cross-Agent Comparison: Context Management Strategies","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/context-management/agent-comparison.md","filePath":"research/concepts/context-management/agent-comparison.md"}'),a={name:"research/concepts/context-management/agent-comparison.md"};function n(i,t,s,c,l,g){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="cross-agent-comparison-context-management-strategies" tabindex="-1">Cross-Agent Comparison: Context Management Strategies <a class="header-anchor" href="#cross-agent-comparison-context-management-strategies" aria-label="Permalink to &quot;Cross-Agent Comparison: Context Management Strategies&quot;">​</a></h1><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>This document provides a comprehensive side-by-side comparison of context management strategies across <strong>17 coding agents</strong>: OpenHands, Codex, Gemini CLI, OpenCode, Goose, Claude Code, Aider, ForgeCode, mini-SWE-agent, Warp, Ante, Droid, Junie CLI, Pi Coding Agent, Sage Agent, TongAgents, and Capy.</p><p>Context management — how an agent tracks, compresses, persists, and retrieves conversational and code context — is arguably the single most important architectural decision in agent design. It determines how long an agent can work autonomously, how much codebase it can reason about, and how gracefully it degrades as tasks grow complex.</p><p>Use this file as a reference for understanding the landscape. Each section examines one dimension of context management, comparing all 17 agents in tabular form with analysis.</p><p>The agents span the full spectrum: from mini-SWE-agent (zero context management) to OpenHands (10-condenser pipeline with 6-layer architecture). Understanding where each agent sits on this spectrum — and <em>why</em> — reveals the fundamental tradeoffs in agent design.</p><hr><h2 id="_2-context-window-sizes-and-models" tabindex="-1">2. Context Window Sizes and Models <a class="header-anchor" href="#_2-context-window-sizes-and-models" aria-label="Permalink to &quot;2. Context Window Sizes and Models&quot;">​</a></h2><p>The foundation of context management is the raw capacity available. Agents vary dramatically in how much context they can hold and how aggressively they use it. Window size alone does not determine effectiveness — what matters is how intelligently the agent <em>uses</em> the available space.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Primary Model(s)</th><th>Context Window</th><th>How They Use It</th></tr></thead><tbody><tr><td>OpenHands</td><td>Claude 3.5/4, GPT-4o</td><td>128K–200K</td><td>Aggressive — fills then compacts via configurable pipeline</td></tr><tr><td>Codex</td><td>GPT-4o, o3-mini</td><td>128K</td><td>Monitors at 90% capacity, auto-compacts with truncation</td></tr><tr><td>Gemini CLI</td><td>Gemini 2.5 Pro/Flash</td><td>1M–2M</td><td>Leverages full window; compaction rarely needed</td></tr><tr><td>OpenCode</td><td>Claude, GPT-4o, Gemini</td><td>Varies by model</td><td>Uses server-reported usage; compacts at 95% threshold</td></tr><tr><td>Goose</td><td>Multiple providers</td><td>Varies</td><td>Proactive compaction at 80%, reactive on token-limit errors</td></tr><tr><td>Claude Code</td><td>Claude 3.5/4</td><td>200K</td><td>Auto-compaction + manual <code>/compact</code> command</td></tr><tr><td>Aider</td><td>Multiple models</td><td>Varies</td><td>Repo-map + token budgets prevent overflow proactively</td></tr><tr><td>ForgeCode</td><td>Multiple</td><td>200K typical</td><td>Bounded context per sub-agent; no single agent sees full history</td></tr><tr><td>mini-SWE-agent</td><td>Various</td><td>128K–200K</td><td>No compaction — designed to fit entirely in window</td></tr><tr><td>Warp</td><td>Multiple</td><td>Varies</td><td>User-initiated compaction via <code>/fork-and-compact</code></td></tr><tr><td>Ante</td><td>Multiple</td><td>Varies</td><td>Distributed across meta-agent + specialized sub-agents</td></tr><tr><td>Droid</td><td>Multiple</td><td>Large</td><td>Incremental compression with anchor points</td></tr><tr><td>Junie CLI</td><td>JetBrains AI models</td><td>Varies</td><td>Token-budget allocation across multi-model routing</td></tr><tr><td>Pi Coding Agent</td><td>Multiple</td><td>Varies</td><td>Tree-structured history with branching</td></tr><tr><td>Sage Agent</td><td>Multiple</td><td>Varies</td><td>Basic context management, minimal sophistication</td></tr><tr><td>TongAgents</td><td>Multiple</td><td>Varies</td><td>Multi-agent distribution across specialized roles</td></tr><tr><td>Capy</td><td>Multiple</td><td>Varies</td><td>Spec document serves as context boundary between agents</td></tr></tbody></table><p><strong>Key Observation:</strong> Gemini CLI&#39;s 1M–2M window fundamentally changes the game — it can hold entire codebases in context, making compaction largely unnecessary. Most other agents must actively manage 128K–200K windows.</p><hr><h2 id="_3-compaction-strategies-per-agent" tabindex="-1">3. Compaction Strategies Per Agent <a class="header-anchor" href="#_3-compaction-strategies-per-agent" aria-label="Permalink to &quot;3. Compaction Strategies Per Agent&quot;">​</a></h2><p>Compaction is how agents deal with context overflow. The approaches range from &quot;do nothing&quot; to sophisticated multi-stage pipelines. This is where the most innovation is happening across the ecosystem.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Primary Strategy</th><th>Secondary Strategy</th><th>LLM-Based?</th><th>Trigger</th></tr></thead><tbody><tr><td>OpenHands</td><td>Configurable condenser pipeline</td><td>10 condenser types available</td><td>Yes (optional)</td><td>Event count threshold (default: 100)</td></tr><tr><td>Codex</td><td>Per-item truncation (oldest first)</td><td>Global truncation pass</td><td>No</td><td>90% of context window</td></tr><tr><td>Gemini CLI</td><td>Rarely needed at 1M+</td><td>Checkpoint-based via shadow git</td><td>Minimal</td><td>Manual or on very long sessions</td></tr><tr><td>OpenCode</td><td>LLM summarization of history</td><td>Full conversation replacement</td><td>Yes</td><td>95% of context window</td></tr><tr><td>Goose</td><td>Tool-pair background summarization</td><td>3-level compaction hierarchy</td><td>Yes</td><td>80% proactive threshold</td></tr><tr><td>Claude Code</td><td>LLM summarization</td><td>Auto-trigger + <code>/compact</code> command</td><td>Yes</td><td>Automatic threshold detection</td></tr><tr><td>Aider</td><td>Repo-map (proactive prevention)</td><td>Token budgets per category</td><td>No</td><td>Budget-based, not reactive</td></tr><tr><td>ForgeCode</td><td>Sub-agent partitioning</td><td>Semantic entry-point analysis</td><td>No</td><td>By architectural design</td></tr><tr><td>mini-SWE-agent</td><td>None — no compaction</td><td>Output truncation only</td><td>No</td><td>Never triggers</td></tr><tr><td>Warp</td><td><code>/fork-and-compact</code></td><td>User-initiated only</td><td>Yes</td><td>Manual user command</td></tr><tr><td>Ante</td><td>Sub-agent distribution</td><td>Meta-agent summarization</td><td>Minimal</td><td>Architectural — by design</td></tr><tr><td>Droid</td><td>Incremental compression</td><td>Anchor point preservation</td><td>Yes</td><td>Continuous, ongoing</td></tr><tr><td>Junie CLI</td><td>Token-budget allocation</td><td>Context routing across models</td><td>Minimal</td><td>Budget threshold</td></tr><tr><td>Pi Coding Agent</td><td>Tree branching (fork history)</td><td><code>/fork</code> command</td><td>No</td><td>Manual user decision</td></tr><tr><td>Sage Agent</td><td>Basic truncation</td><td>None</td><td>No</td><td>Window limit</td></tr><tr><td>TongAgents</td><td>Agent-level distribution</td><td>Role-based partitioning</td><td>No</td><td>By design</td></tr><tr><td>Capy</td><td>Spec document boundary</td><td>Captain/Build agent split</td><td>Yes</td><td>Architectural boundary</td></tr></tbody></table><p><strong>Key Observation:</strong> There is a clear divide between LLM-based compaction (OpenHands, OpenCode, Goose, Claude Code, Droid) and structural compaction (ForgeCode, Ante, Capy). LLM-based approaches preserve semantic content but cost tokens; structural approaches avoid the problem entirely through architecture.</p><hr><h2 id="_4-token-counting-approaches" tabindex="-1">4. Token Counting Approaches <a class="header-anchor" href="#_4-token-counting-approaches" aria-label="Permalink to &quot;4. Token Counting Approaches&quot;">​</a></h2><p>Accurate token counting is critical for knowing <em>when</em> to compact. Agents vary widely in precision.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Method</th><th>Accuracy</th><th>Client Library</th><th>Cost Tracking</th></tr></thead><tbody><tr><td>Aider</td><td>Exact tokenizer + sampling fallback</td><td>High</td><td>tiktoken</td><td>Basic per-session</td></tr><tr><td>Codex</td><td>Byte heuristic (4 bytes/token)</td><td>Medium (~15% variance)</td><td>None (custom)</td><td>Cumulative across session</td></tr><tr><td>OpenCode</td><td>Server-reported usage only</td><td>Exact (post-hoc)</td><td>None</td><td>Per-turn cost display</td></tr><tr><td>Goose</td><td>Provider-specific tokenizers</td><td>Varies by provider</td><td>Varies</td><td>Yes, per-provider</td></tr><tr><td>Claude Code</td><td>Internal Anthropic counting</td><td>N/A (integrated)</td><td>Integrated SDK</td><td><code>/context</code> command</td></tr><tr><td>Gemini CLI</td><td>Gemini API reporting</td><td>High</td><td>Google SDK</td><td>Built-in</td></tr><tr><td>Junie CLI</td><td>Pre-computed token budgets</td><td>Medium</td><td>Varies by model</td><td>Yes</td></tr><tr><td>Warp</td><td>Pre-computed budgets</td><td>Medium</td><td>Varies</td><td>Yes</td></tr><tr><td>OpenHands</td><td>Model-specific estimation</td><td>Medium-High</td><td>Varies</td><td>Per-event tracking</td></tr><tr><td>ForgeCode</td><td>Per-agent budget tracking</td><td>Medium</td><td>Varies</td><td>Per-agent</td></tr><tr><td>Droid</td><td>Server-reported + estimation</td><td>Medium-High</td><td>Varies</td><td>Cross-session</td></tr><tr><td>Pi Coding Agent</td><td>Basic estimation</td><td>Low-Medium</td><td>Varies</td><td>Minimal</td></tr><tr><td>mini-SWE-agent</td><td>Basic or none</td><td>Low</td><td>None</td><td>Trajectory-level</td></tr><tr><td>Ante</td><td>Per-agent estimation</td><td>Medium</td><td>Varies</td><td>Distributed</td></tr><tr><td>TongAgents</td><td>Per-agent estimation</td><td>Medium</td><td>Varies</td><td>Per-role</td></tr><tr><td>Sage Agent</td><td>Basic estimation</td><td>Low</td><td>Varies</td><td>Minimal</td></tr><tr><td>Capy</td><td>Per-agent budget</td><td>Medium</td><td>Varies</td><td>Per-phase</td></tr></tbody></table><p><strong>Key Observation:</strong> Only Aider invests in client-side exact tokenization (via tiktoken). Codex takes the opposite extreme with a simple byte-heuristic. Most agents rely on server-reported usage, which is accurate but only available <em>after</em> the API call — too late to prevent overflow on the current turn.</p><hr><h2 id="_5-memory-and-persistence-systems" tabindex="-1">5. Memory and Persistence Systems <a class="header-anchor" href="#_5-memory-and-persistence-systems" aria-label="Permalink to &quot;5. Memory and Persistence Systems&quot;">​</a></h2><p>How agents remember across sessions and provide persistent context.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Memory File</th><th>Auto-Memory</th><th>Session Storage</th><th>Resume Mechanism</th></tr></thead><tbody><tr><td>Claude Code</td><td>CLAUDE.md (hierarchical)</td><td>Yes (auto-writes MEMORY.md)</td><td>Session store</td><td><code>--resume</code>, <code>--name</code></td></tr><tr><td>Gemini CLI</td><td>GEMINI.md (hierarchical)</td><td>No</td><td>Shadow git repo</td><td><code>/restore</code> command</td></tr><tr><td>OpenCode</td><td>OpenCode.md</td><td>No</td><td>SQLite database</td><td>Session selection UI</td></tr><tr><td>Goose</td><td>.goosehints + AGENTS.md</td><td>No</td><td>File-based sessions</td><td>Session management</td></tr><tr><td>Warp</td><td>AGENTS.md</td><td>No</td><td>Warp Drive (cloud)</td><td>Cross-device sync</td></tr><tr><td>ForgeCode</td><td>AGENTS.md</td><td>No</td><td>N/A</td><td>N/A</td></tr><tr><td>Aider</td><td>None built-in</td><td>No</td><td>diskcache (SQLite)</td><td><code>--restore-chat-history</code></td></tr><tr><td>OpenHands</td><td>None</td><td>No</td><td>EventStream (JSON)</td><td>Event replay</td></tr><tr><td>Codex</td><td>None</td><td>No</td><td>In-memory only</td><td>GhostSnapshot rollback</td></tr><tr><td>Pi Coding Agent</td><td>None</td><td>No</td><td>JSONL tree structure</td><td><code>/tree</code>, <code>/fork</code></td></tr><tr><td>Droid</td><td>None (reported auto-memory)</td><td>Reported</td><td>Cloud storage</td><td>Cross-interface resume</td></tr><tr><td>Junie CLI</td><td>None</td><td>No</td><td>IDE-integrated</td><td>IDE session management</td></tr><tr><td>mini-SWE-agent</td><td>None</td><td>No</td><td>Full trajectory JSON</td><td>Direct trajectory replay</td></tr><tr><td>Ante</td><td>None</td><td>No</td><td>Distributed state</td><td>Meta-agent state</td></tr><tr><td>TongAgents</td><td>None</td><td>No</td><td>Per-agent state</td><td>N/A</td></tr><tr><td>Sage Agent</td><td>None</td><td>No</td><td>Minimal</td><td>N/A</td></tr><tr><td>Capy</td><td>Spec document</td><td>No</td><td>Phase-based</td><td>Spec continuity</td></tr></tbody></table><p><strong>Key Observation:</strong> Claude Code&#39;s CLAUDE.md has become an informal standard — Gemini CLI (GEMINI.md), OpenCode (OpenCode.md), and multiple agents (AGENTS.md) have adopted the same hierarchical memory-file pattern. Auto-memory (automatically learning preferences) remains rare; only Claude Code implements it meaningfully.</p><hr><h2 id="_6-architecture-comparison" tabindex="-1">6. Architecture Comparison <a class="header-anchor" href="#_6-architecture-comparison" aria-label="Permalink to &quot;6. Architecture Comparison&quot;">​</a></h2><p>The highest-level view: how each agent structures its context management. Architecture choices ripple through every other dimension — they determine what compaction strategies are possible, how memory works, and what the ceiling is for task complexity.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Single/Multi Agent</th><th>Context Philosophy</th><th>Unique Innovation</th></tr></thead><tbody><tr><td>OpenHands</td><td>Single (configurable)</td><td>Fill aggressively, then compact</td><td>10-condenser pipeline with 6-layer architecture</td></tr><tr><td>Codex</td><td>Single</td><td>Conservative truncation</td><td>Byte-based estimation + GhostSnapshot rollback</td></tr><tr><td>Gemini CLI</td><td>Single</td><td>Leverage massive 1M+ window</td><td>Shadow git checkpointing for state recovery</td></tr><tr><td>OpenCode</td><td>Single</td><td>Server-reported, auto-compact</td><td>SQLite persistence with multi-provider support</td></tr><tr><td>Goose</td><td>Single</td><td>3-level hierarchical compaction</td><td>Tool-pair background summarization + MOIM extensions</td></tr><tr><td>Claude Code</td><td>Multi (sub-agents)</td><td>Partition work across windows</td><td>Sub-agents as a context management strategy</td></tr><tr><td>Aider</td><td>Single</td><td>Proactive prevention</td><td>tree-sitter + PageRank-based repo-map</td></tr><tr><td>ForgeCode</td><td>Multi (3-agent pipeline)</td><td>Bounded context per agent</td><td>Semantic entry-point analysis — 93% fewer tokens</td></tr><tr><td>mini-SWE-agent</td><td>Single</td><td>No compaction needed</td><td>Linear history doubles as training data</td></tr><tr><td>Warp</td><td>Single</td><td>User-controlled compaction</td><td><code>/fork-and-compact</code> with cloud persistence</td></tr><tr><td>Ante</td><td>Multi (meta + sub)</td><td>Distributed across agents</td><td>Meta-agent coordination pattern</td></tr><tr><td>Droid</td><td>Single</td><td>Incremental compression</td><td>Confidence-scored compression for multi-week sessions</td></tr><tr><td>Junie CLI</td><td>Single</td><td>Budget allocation</td><td>JetBrains IDE integration + multi-model routing</td></tr><tr><td>Pi Coding Agent</td><td>Single</td><td>Tree-structured branching</td><td>JSONL tree with <code>/fork</code> for exploration</td></tr><tr><td>Capy</td><td>Multi (2-agent)</td><td>Spec document as boundary</td><td>Captain/Build architecture with spec handoff</td></tr><tr><td>TongAgents</td><td>Multi</td><td>Multi-agent distribution</td><td>Specialized agent roles with distinct contexts</td></tr><tr><td>Sage Agent</td><td>Single</td><td>Basic management</td><td>Minimal approach — simplicity as strategy</td></tr></tbody></table><hr><h2 id="_7-proactive-vs-reactive-strategies" tabindex="-1">7. Proactive vs Reactive Strategies <a class="header-anchor" href="#_7-proactive-vs-reactive-strategies" aria-label="Permalink to &quot;7. Proactive vs Reactive Strategies&quot;">​</a></h2><p>A critical distinction: does the agent <em>prevent</em> context overflow or <em>react</em> to it?</p><table tabindex="0"><thead><tr><th>Agent</th><th>Proactive Strategies</th><th>Reactive Strategies</th></tr></thead><tbody><tr><td>OpenHands</td><td>Event-count threshold triggers compaction early</td><td>Falls back through condenser pipeline on overflow</td></tr><tr><td>Codex</td><td>Monitors usage at 90% to compact before overflow</td><td>Truncates oldest items on token-limit API errors</td></tr><tr><td>Gemini CLI</td><td>1M+ window makes overflow rare by design</td><td>Shadow git checkpoint restore on failure</td></tr><tr><td>OpenCode</td><td>Server-reported tracking enables early warning</td><td>LLM summarization when 95% threshold hit</td></tr><tr><td>Goose</td><td>80% threshold + background tool-pair summarization</td><td>3-level reactive compaction + API error retry</td></tr><tr><td>Claude Code</td><td>Sub-agent delegation prevents single-window overflow</td><td>Auto-compaction + <code>/compact</code> for manual recovery</td></tr><tr><td>Aider</td><td>Repo-map keeps only relevant code in context</td><td>Token budgets drop lowest-priority content first</td></tr><tr><td>ForgeCode</td><td>3-agent architecture bounds context by design</td><td>Semantic entry-point reduces input at parse time</td></tr><tr><td>mini-SWE-agent</td><td>Designed for short tasks that fit in window</td><td>Output truncation is the only reactive measure</td></tr><tr><td>Warp</td><td>AGENTS.md provides persistent context cheaply</td><td><code>/fork-and-compact</code> when user notices degradation</td></tr><tr><td>Ante</td><td>Meta-agent distributes work before context fills</td><td>Sub-agent isolation prevents cross-contamination</td></tr><tr><td>Droid</td><td>Continuous incremental compression</td><td>Anchor-point preservation on aggressive compression</td></tr><tr><td>Junie CLI</td><td>Multi-model routing sends tasks to optimal model</td><td>Budget reallocation when limits approached</td></tr><tr><td>Pi Coding Agent</td><td>Tree branching lets users explore without bloating main</td><td><code>/fork</code> discards exploration branches</td></tr><tr><td>Sage Agent</td><td>None significant</td><td>Basic truncation on overflow</td></tr><tr><td>TongAgents</td><td>Role-based distribution prevents single-agent bloat</td><td>Agent-level context clearing</td></tr><tr><td>Capy</td><td>Spec document bounds what each agent sees</td><td>Captain re-plans if Build agent context exhausted</td></tr></tbody></table><p><strong>Key Observation:</strong> The most effective agents combine proactive <em>and</em> reactive strategies. Goose exemplifies this: 80% proactive threshold + background summarization + 3-level reactive fallback. Pure reactive approaches (Sage Agent, mini-SWE-agent) only work for short tasks.</p><h3 id="strategy-effectiveness-matrix" tabindex="-1">Strategy Effectiveness Matrix <a class="header-anchor" href="#strategy-effectiveness-matrix" aria-label="Permalink to &quot;Strategy Effectiveness Matrix&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Strategy Type</th><th>Best For</th><th>Worst For</th><th>Example Agents</th></tr></thead><tbody><tr><td>Pure proactive (prevention)</td><td>Large codebases, known structure</td><td>Exploratory tasks</td><td>Aider, ForgeCode</td></tr><tr><td>Pure reactive (compression)</td><td>Short-medium tasks</td><td>Long autonomous runs</td><td>Codex, Sage Agent</td></tr><tr><td>Hybrid (proactive + reactive)</td><td>General purpose, long sessions</td><td>Simple quick fixes (overkill)</td><td>Goose, Claude Code, OpenHands</td></tr><tr><td>Architectural (multi-agent)</td><td>Complex multi-step workflows</td><td>Simple single-file edits</td><td>ForgeCode, Ante, Capy</td></tr><tr><td>Avoidance (big window)</td><td>Everything up to window limit</td><td>Tasks exceeding even 1M tokens</td><td>Gemini CLI</td></tr></tbody></table><hr><h2 id="_8-the-spectrum-simplest-to-most-sophisticated" tabindex="-1">8. The Spectrum: Simplest to Most Sophisticated <a class="header-anchor" href="#_8-the-spectrum-simplest-to-most-sophisticated" aria-label="Permalink to &quot;8. The Spectrum: Simplest to Most Sophisticated&quot;">​</a></h2><p>Ranking all 17 agents from simplest to most complex context management:</p><table tabindex="0"><thead><tr><th>Rank</th><th>Agent</th><th>Sophistication</th><th>Why This Ranking</th></tr></thead><tbody><tr><td>1</td><td>mini-SWE-agent</td><td>None</td><td>No compaction at all — relies on fitting in window</td></tr><tr><td>2</td><td>Sage Agent</td><td>Basic</td><td>Minimal truncation, no persistence, no memory files</td></tr><tr><td>3</td><td>Pi Coding Agent</td><td>Low</td><td>Tree branching is clever but manual; no auto-compaction</td></tr><tr><td>4</td><td>TongAgents</td><td>Low-Medium</td><td>Multi-agent distribution but basic per-agent management</td></tr><tr><td>5</td><td>Codex</td><td>Medium</td><td>Truncation + byte heuristic — simple but effective</td></tr><tr><td>6</td><td>OpenCode</td><td>Medium</td><td>LLM summarization + SQLite — solid single-agent approach</td></tr><tr><td>7</td><td>Warp</td><td>Medium</td><td>User-controlled + AGENTS.md + cloud persistence</td></tr><tr><td>8</td><td>Gemini CLI</td><td>Medium-High</td><td>1M window + shadow git — sidesteps the problem elegantly</td></tr><tr><td>9</td><td>Goose</td><td>High</td><td>3-level compaction + MOIM + tool-pair summarization</td></tr><tr><td>10</td><td>Aider</td><td>High</td><td>Repo-map (tree-sitter + PageRank) + token budgets</td></tr><tr><td>11</td><td>Claude Code</td><td>High</td><td>Sub-agents + auto-memory + hierarchical CLAUDE.md</td></tr><tr><td>12</td><td>Junie CLI</td><td>High</td><td>Multi-model routing + budget allocation + IDE integration</td></tr><tr><td>13</td><td>Capy</td><td>High</td><td>Captain/Build + spec-document boundary</td></tr><tr><td>14</td><td>Ante</td><td>High</td><td>Meta-agent coordination + distributed context</td></tr><tr><td>15</td><td>ForgeCode</td><td>Very High</td><td>3-agent pipeline + semantic entry-point — 93% token savings</td></tr><tr><td>16</td><td>Droid</td><td>Very High</td><td>Incremental compression + confidence scoring + multi-week</td></tr><tr><td>17</td><td>OpenHands</td><td>Very High</td><td>10-condenser pipeline + 6-layer architecture + full config</td></tr></tbody></table><p><strong>Note:</strong> Higher sophistication does not always mean better. mini-SWE-agent&#39;s &quot;no compaction&quot; approach works perfectly for short, well-scoped tasks. Gemini CLI&#39;s strategy of &quot;just use a bigger window&quot; is arguably the most practical. The right level of sophistication depends on task duration, codebase size, and autonomy requirements.</p><hr><h2 id="_9-cross-cutting-dimensions" tabindex="-1">9. Cross-Cutting Dimensions <a class="header-anchor" href="#_9-cross-cutting-dimensions" aria-label="Permalink to &quot;9. Cross-Cutting Dimensions&quot;">​</a></h2><h3 id="_9a-multi-agent-vs-single-agent-context-distribution" tabindex="-1">9a. Multi-Agent vs Single-Agent Context Distribution <a class="header-anchor" href="#_9a-multi-agent-vs-single-agent-context-distribution" aria-label="Permalink to &quot;9a. Multi-Agent vs Single-Agent Context Distribution&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Approach</th><th>Agents</th><th>Tradeoffs</th></tr></thead><tbody><tr><td>Single-agent, no compaction</td><td>mini-SWE-agent, Sage Agent</td><td>Simple but limited to short tasks</td></tr><tr><td>Single-agent, reactive compaction</td><td>Codex, OpenCode, Warp</td><td>Works for medium tasks; quality degrades on long ones</td></tr><tr><td>Single-agent, proactive management</td><td>Aider, Goose, Droid, Junie CLI</td><td>Best single-agent approaches; Aider&#39;s repo-map is standout</td></tr><tr><td>Multi-agent, partitioned context</td><td>Claude Code, ForgeCode, Capy, Ante, TongAgents</td><td>Highest token efficiency; most architectural complexity</td></tr></tbody></table><h3 id="_9b-memory-file-adoption" tabindex="-1">9b. Memory File Adoption <a class="header-anchor" href="#_9b-memory-file-adoption" aria-label="Permalink to &quot;9b. Memory File Adoption&quot;">​</a></h3><p>The CLAUDE.md pattern has spawned an ecosystem:</p><ul><li><strong>CLAUDE.md</strong> → Claude Code (the originator)</li><li><strong>GEMINI.md</strong> → Gemini CLI (direct adaptation)</li><li><strong>OpenCode.md</strong> → OpenCode (same pattern)</li><li><strong>AGENTS.md</strong> → Goose, Warp, ForgeCode (standardized variant)</li><li><strong>.goosehints</strong> → Goose (additional layer)</li><li><strong>Spec documents</strong> → Capy (functional equivalent)</li><li><strong>None</strong> → OpenHands, Codex, Aider, mini-SWE-agent, Pi Coding Agent</li></ul><h3 id="_9c-session-persistence-approaches" tabindex="-1">9c. Session Persistence Approaches <a class="header-anchor" href="#_9c-session-persistence-approaches" aria-label="Permalink to &quot;9c. Session Persistence Approaches&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Approach</th><th>Agents</th><th>Durability</th></tr></thead><tbody><tr><td>In-memory only</td><td>Codex</td><td>Lost on exit (GhostSnapshot for rollback only)</td></tr><tr><td>File-based JSON/JSONL</td><td>OpenHands, Goose, Pi Coding Agent, mini-SWE-agent</td><td>Durable, human-readable</td></tr><tr><td>SQLite database</td><td>OpenCode, Aider</td><td>Durable, queryable</td></tr><tr><td>Cloud storage</td><td>Warp, Droid</td><td>Cross-device, highest durability</td></tr><tr><td>Shadow git repo</td><td>Gemini CLI</td><td>Durable + versioned state</td></tr><tr><td>IDE-integrated</td><td>Junie CLI</td><td>Tied to IDE session lifecycle</td></tr></tbody></table><hr><h2 id="_10-key-insights" tabindex="-1">10. Key Insights <a class="header-anchor" href="#_10-key-insights" aria-label="Permalink to &quot;10. Key Insights&quot;">​</a></h2><h3 id="no-single-approach-dominates" tabindex="-1">No Single Approach Dominates <a class="header-anchor" href="#no-single-approach-dominates" aria-label="Permalink to &quot;No Single Approach Dominates&quot;">​</a></h3><p>The landscape reveals no universal winner. Each strategy excels in specific contexts:</p><ul><li><strong>Short tasks</strong> → mini-SWE-agent&#39;s simplicity is ideal</li><li><strong>Large codebases</strong> → Aider&#39;s repo-map or Gemini CLI&#39;s 1M window</li><li><strong>Long autonomous sessions</strong> → Droid&#39;s incremental compression or OpenHands&#39; pipeline</li><li><strong>Multi-step workflows</strong> → ForgeCode&#39;s 3-agent pipeline or Capy&#39;s Captain/Build</li></ul><h3 id="proactive-beats-reactive" tabindex="-1">Proactive Beats Reactive <a class="header-anchor" href="#proactive-beats-reactive" aria-label="Permalink to &quot;Proactive Beats Reactive&quot;">​</a></h3><p>Agents that prevent context bloat consistently outperform those that compress after the fact. Aider&#39;s repo-map (only loading relevant code) and ForgeCode&#39;s semantic entry-point (93% fewer tokens) demonstrate that <em>not putting tokens in context</em> is better than <em>removing them later</em>.</p><h3 id="multi-agent-largest-token-savings-most-complexity" tabindex="-1">Multi-Agent = Largest Token Savings, Most Complexity <a class="header-anchor" href="#multi-agent-largest-token-savings-most-complexity" aria-label="Permalink to &quot;Multi-Agent = Largest Token Savings, Most Complexity&quot;">​</a></h3><p>ForgeCode&#39;s 93% token reduction is the standout metric. But multi-agent architectures introduce coordination overhead, potential information loss at boundaries, and debugging complexity. The tradeoff is worth it for complex, long-running tasks but overkill for quick fixes.</p><h3 id="simple-approaches-work-surprisingly-well" tabindex="-1">Simple Approaches Work Surprisingly Well <a class="header-anchor" href="#simple-approaches-work-surprisingly-well" aria-label="Permalink to &quot;Simple Approaches Work Surprisingly Well&quot;">​</a></h3><p>mini-SWE-agent achieves competitive benchmark scores with zero context management. For tasks that fit in a single context window (and many real-world tasks do), sophisticated compaction adds complexity without benefit.</p><h3 id="the-trend-smarter-context-not-just-bigger-windows" tabindex="-1">The Trend: Smarter Context, Not Just Bigger Windows <a class="header-anchor" href="#the-trend-smarter-context-not-just-bigger-windows" aria-label="Permalink to &quot;The Trend: Smarter Context, Not Just Bigger Windows&quot;">​</a></h3><p>While Gemini CLI proves bigger windows help, the broader trend is toward <em>smarter</em> context management:</p><ul><li><strong>Structural prevention</strong> (ForgeCode, Aider) over reactive compression</li><li><strong>Hierarchical memory</strong> (CLAUDE.md pattern) for cross-session persistence</li><li><strong>Multi-agent distribution</strong> for complex tasks</li><li><strong>Confidence-scored compression</strong> (Droid) for quality-aware compaction</li></ul><h3 id="the-emerging-standard-stack" tabindex="-1">The Emerging Standard Stack <a class="header-anchor" href="#the-emerging-standard-stack" aria-label="Permalink to &quot;The Emerging Standard Stack&quot;">​</a></h3><p>A &quot;best practices&quot; context management stack is emerging:</p><ol><li><strong>Memory file</strong> (CLAUDE.md / AGENTS.md) for persistent preferences</li><li><strong>Proactive filtering</strong> (repo-map or semantic analysis) to minimize input</li><li><strong>LLM-based summarization</strong> as the primary compaction strategy</li><li><strong>Token budget system</strong> to allocate context across categories</li><li><strong>Session persistence</strong> (SQLite or file-based) for resume capability</li><li><strong>Sub-agent delegation</strong> for tasks that exceed single-window capacity</li></ol><p>No single agent implements all six perfectly, but Claude Code and Goose come closest.</p><h3 id="what-s-missing-from-all-agents" tabindex="-1">What&#39;s Missing From All Agents <a class="header-anchor" href="#what-s-missing-from-all-agents" aria-label="Permalink to &quot;What&#39;s Missing From All Agents&quot;">​</a></h3><p>Despite rapid progress, several gaps remain across the entire landscape:</p><ul><li><strong>Semantic deduplication</strong> — no agent detects when the same information appears multiple times in context</li><li><strong>User-adaptive compaction</strong> — compaction aggressiveness should vary by user expertise and task type</li><li><strong>Cross-session learning</strong> — only Claude Code attempts to learn from past sessions; most start fresh</li><li><strong>Context quality metrics</strong> — no agent measures whether compacted context actually preserves decision-relevant information</li><li><strong>Collaborative context</strong> — no agent handles multi-user shared context for team workflows</li></ul><hr><p><em>This comparison is based on analysis of open-source repositories, documentation, and published research as of 2025. Agent capabilities evolve rapidly — verify against current versions.</em></p>',74)])])}const h=e(a,[["render",n]]);export{p as __pageData,h as default};
